import { GoogleGenAI } from "@google/genai";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async getMarketInsight(prompt: string): Promise<string> {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: prompt,
        config: {
          systemInstruction: "You are a senior consultant at Ally Partners, a boutique firm in Jersey. Your tone is professional, human-centric, minimalist, and authoritative. Avoid corporate jargon. Provide concise, high-impact insights for alternative asset managers and startups. Always relate back to the Jersey market if possible.",
          temperature: 0.7,
        },
      });

      return response.text || "I'm sorry, I couldn't generate an insight at this moment. Please try again.";
    } catch (error) {
      console.error("Gemini API Error:", error);
      return "An error occurred while fetching market insights. Please check your connection and try again.";
    }
  }
}

export const geminiService = new GeminiService();

