const MarketInsights: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [selectedPromptId, setSelectedPromptId] = useState<string | null>(null);
  const [result, setResult] = useState<InsightResult | null>(null);

  const handlePromptClick = async (id: string, prompt: string) => {
    setSelectedPromptId(id);
    setLoading(true);
    setResult(null);

    const insightText = await geminiService.getMarketInsight(prompt);

    setResult({
      text: insightText,
      timestamp: new Date()
    });
    setLoading(false);
  };

  return (
    <section id="insights" className="py-24 bg-slate-900 text-white relative overflow-hidden">
      {/* Background decorations */}
      <div className="absolute top-0 left-0 w-full h-full opacity-10 pointer-events-none">
        <div className="absolute top-10 left-10 w-96 h-96 bg-blue-500 rounded-full blur-[100px]"></div>
        <div className="absolute bottom-10 right-10 w-96 h-96 bg-indigo-500 rounded-full blur-[100px]"></div>
      </div>

      <div className="max-w-7xl mx-auto px-6 relative z-10">
        <div className="flex flex-col lg:flex-row gap-16">
          <div className="lg:w-1/3">
            <h2 className="text-xs font-bold text-blue-400 uppercase tracking-widest mb-4">Market Intelligence</h2>
            <h3 className="text-4xl font-bold mb-6">Real-time Insights.</h3>
            <p className="text-slate-400 mb-10 leading-relaxed">
              Select a focus area below to generate an AI-powered strategic summary of the current landscape in Jersey and beyond.
            </p>

            <div className="flex flex-col gap-3">
              {INSIGHT_PROMPTS.map((item) => (
                <button
                  key={item.id}
                  onClick={() => handlePromptClick(item.id, item.prompt)}
                  disabled={loading}
                  className={`text-left px-6 py-4 rounded-xl font-medium transition-all flex items-center justify-between border ${
                    selectedPromptId === item.id 
                      ? 'bg-blue-600 border-blue-500 text-white shadow-lg shadow-blue-900/40' 
                      : 'bg-white/5 border-white/10 text-slate-300 hover:bg-white/10 hover:border-white/20'
                  } disabled:opacity-50`}
                >
                  {item.label}
                  <i className={`fa-solid ${selectedPromptId === item.id && loading ? 'fa-spinner fa-spin' : 'fa-chevron-right text-xs opacity-50'}`}></i>
                </button>
              ))}
            </div>
          </div>

          <div className="lg:w-2/3">
            <div className="bg-white/5 border border-white/10 rounded-3xl p-8 h-full min-h-[400px] flex flex-col">
              {!selectedPromptId && !result && (
                <div className="flex-1 flex flex-col items-center justify-center text-center p-8">
                  <div className="w-20 h-20 bg-blue-500/20 rounded-full flex items-center justify-center mb-6">
                    <i className="fa-solid fa-brain text-3xl text-blue-400"></i>
                  </div>
                  <h4 className="text-xl font-bold mb-2 text-slate-200">Ready to assist</h4>
                  <p className="text-slate-500 max-w-sm">Select a category on the left to pull data from our intelligence engine.</p>
                </div>
              )}

              {loading && (
                <div className="flex-1 flex flex-col items-center justify-center text-center p-8">
                  <div className="flex gap-1 mb-6">
                    <div className="w-2 h-2 bg-blue-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                    <div className="w-2 h-2 bg-blue-400 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                    <div className="w-2 h-2 bg-blue-400 rounded-full animate-bounce"></div>
                  </div>
                  <p className="text-slate-400 font-mono text-sm uppercase tracking-tighter">Synthesizing operational data...</p>
                </div>
              )}

              {result && !loading && (
                <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
                  <div className="flex items-center justify-between mb-8 border-b border-white/10 pb-4">
                    <span className="text-blue-400 font-mono text-xs uppercase tracking-widest flex items-center gap-2">
                      <span className="w-2 h-2 bg-green-500 rounded-full"></span> Generated Intelligence
                    </span>
                    <span className="text-slate-500 text-xs">
                      {result.timestamp.toLocaleTimeString()}
                    </span>
                  </div>
                  <div className="prose prose-invert max-w-none">
                    <div className="text-slate-200 text-lg leading-relaxed whitespace-pre-line">
                      {result.text}
                    </div>
                  </div>
                  <div className="mt-10 p-4 bg-white/5 rounded-xl border border-white/10 flex items-center gap-3">
                    <i className="fa-solid fa-circle-info text-blue-400"></i>
                    <p className="text-xs text-slate-400">
