import { GoogleGenAI } from "@google/genai";
import { INSIGHT_PROMPTS } from "../constants";

export class GeminiService {
  /**
   * Fetches market insight for a specific predefined prompt ID.
   * Implements daily caching in localStorage to minimize API calls.
   * strictly enforces that only suggested prompts can be run.
   */
  async getMarketInsight(id: string): Promise<string> {
    // 1. Validate ID against predefined prompts (Anti-backdoor measure)
    const promptConfig = INSIGHT_PROMPTS.find(p => p.id === id);
    if (!promptConfig) {
      console.error(`Unauthorized prompt ID: ${id}`);
      return "Invalid request. Please select a valid insight category.";
    }

    // 2. Check Daily Cache
    const today = new Date().toISOString().split('T')[0]; // YYYY-MM-DD
    const cacheKey = `ally_insight_${id}_${today}`;

    try {
      if (typeof localStorage !== 'undefined') {
        const cachedResponse = localStorage.getItem(cacheKey);
        if (cachedResponse) {
          console.debug(`Serving cached insight for: ${id}`);
          return cachedResponse;
        }
        // Clean up old cache entries
        this.clearOldCaches(today);
      }
    } catch (e) {
      console.warn("Storage access failed:", e);
    }

    // 3. Fetch from Gemini if not cached
    try {
      // Use process.env.API_KEY as per instructions, assuming it is pre-configured.
      // We wrap this in a try-catch to ensure any environment-level ReferenceErrors 
      // are caught and handled gracefully in the UI.
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: promptConfig.prompt,
        config: {
          systemInstruction: "You are a senior consultant at Ally Partners, a boutique firm in Jersey. Your tone is professional, human-centric, minimalist, and authoritative. Avoid corporate jargon. Provide high-impact insights for alternative asset managers and startups. Always relate back to the Jersey market. CRITICAL: Your response must be extremely brief and fit within 500 characters.",
          temperature: 0.7,
        },
      });

      const resultText = response.text || "I'm sorry, I couldn't generate an insight at this moment.";

      // Save to cache for today
      try {
        if (typeof localStorage !== 'undefined') {
          localStorage.setItem(cacheKey, resultText);
        }
      } catch (e) {
        // Silently fail if quota exceeded or storage blocked
      }

      return resultText;
    } catch (error) {
      console.error("Gemini API Error:", error);
      throw error; // Rethrow to let the component handle the UI state
    }
  }

  private clearOldCaches(currentDate: string) {
    if (typeof localStorage === 'undefined') return;
    try {
      const keysToRemove: string[] = [];
      for (let i = 0; i < localStorage.length; i++) {
        const key = localStorage.key(i);
        if (key?.startsWith('ally_insight_') && !key.endsWith(currentDate)) {
          keysToRemove.push(key);
        }
      }
      keysToRemove.forEach(k => {
        try {
          localStorage.removeItem(k);
        } catch(e) {}
      });
    } catch (e) {
      // Ignore storage errors
    }
  }
}

export const geminiService = new GeminiService();

import React, { useState, useEffect } from 'react';
import { INSIGHT_PROMPTS } from '../constants';
import { InsightResult } from '../types';
import { geminiService } from '../services/geminiService';

const MarketInsights: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [selectedPromptId, setSelectedPromptId] = useState<string | null>(null);
  const [result, setResult] = useState<InsightResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    // Auto-load the first prompt on mount
    const initialPrompt = INSIGHT_PROMPTS[0];
    if (initialPrompt) {
      handlePromptClick(initialPrompt.id).catch(err => {
        console.error("Initial insight load failed:", err);
      });
    }
  }, []);

  const handlePromptClick = async (id: string) => {
    // Prevent re-fetching if already loading the same prompt
    if (loading && selectedPromptId === id) return;

    setSelectedPromptId(id);
    setLoading(true);
    setError(null);

    try {
      // We only pass the ID to ensure the service uses the fixed prompts
      const insightText = await geminiService.getMarketInsight(id);

      setResult({
        text: insightText,
        timestamp: new Date()
      });
    } catch (err) {
      console.error("Failed to fetch insight:", err);
      setError("Unable to refresh live insights. Using latest strategic brief.");
      // Fallback content to ensure UI remains functional and looks good
      setResult({
        text: "Efficiency in alternative asset management is no longer a luxury; it is the primary differentiator for 2025. Jersey-based firms are increasingly leading the shift toward fully automated middle-office operations.",
        timestamp: new Date()
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <section id="insights" className="py-24 bg-zinc-950 text-white relative overflow-hidden">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(59,130,246,0.05)_0%,transparent_100%)]"></div>

      <div className="max-w-5xl mx-auto px-6 relative z-10">
        <div className="text-center mb-12">
          <h2 className="text-blue-500 font-bold text-[10px] uppercase tracking-[0.3em] mb-4">Intelligence Engine</h2>
          <h3 className="text-3xl font-bold tracking-tight">Real-time Strategic Summaries.</h3>
        </div>

        <div className="flex flex-col items-center">
          {/* Smaller, minimalist prompt selector */}
          <div className="flex flex-wrap justify-center gap-2 mb-12 p-1.5 bg-zinc-900 rounded-2xl border border-white/5">
            {INSIGHT_PROMPTS.map((item) => (
              <button
                key={item.id}
                onClick={() => handlePromptClick(item.id)}
                disabled={loading}
                className={`px-5 py-2.5 rounded-xl text-[11px] font-bold uppercase tracking-wider transition-all ${
                  selectedPromptId === item.id 
                    ? 'bg-blue-600 text-white shadow-lg' 
                    : 'text-zinc-500 hover:text-zinc-300 hover:bg-white/5'
                } disabled:opacity-50`}
              >
                {item.label}
              </button>
            ))}
          </div>

          {/* Insight Result - Quote Style */}
          <div className="w-full max-w-4xl min-h-[320px] relative flex flex-col items-center justify-center text-center px-6">
            {loading ? (
              <div className="flex flex-col items-center animate-pulse">
                <div className="flex gap-1.5 mb-6">
                  <div className="w-2 h-2 bg-blue-500 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                  <div className="w-2 h-2 bg-blue-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                  <div className="w-2 h-2 bg-blue-500 rounded-full animate-bounce"></div>
                </div>
                <p className="text-zinc-500 font-mono text-[10px] uppercase tracking-widest">Synthesizing Brief...</p>
              </div>
            ) : result ? (
              <div className="animate-in fade-in zoom-in-95 duration-700">
                <div className="text-blue-500/20 text-8xl font-serif absolute -top-10 left-0 -z-10 select-none">“</div>
                <blockquote className="text-2xl md:text-3xl font-medium text-zinc-100 leading-tight mb-8 max-w-2xl italic">
                  {result.text}
                </blockquote>
                {error && <p className="text-[10px] text-zinc-600 mb-6 font-bold uppercase tracking-widest">{error}</p>}
                <div className="flex items-center justify-center gap-3">
                  <div className="h-px w-8 bg-zinc-800"></div>
                  <span className="text-[10px] font-bold text-zinc-500 uppercase tracking-[0.2em]">
                    Ally AI Consultant • {result.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                  </span>
                  <div className="h-px w-8 bg-zinc-800"></div>
                </div>
              </div>
            ) : null}
          </div>
        </div>
      </div>
    </section>
  );
};

