const App: React.FC = () => {
  const [view, setView] = useState<'home' | 'contact'>('home');

  // Handle browser back button and initial state
  useEffect(() => {
    const handlePopState = () => {
      const path = window.location.hash;
      if (path === '#contact-form') {
        setView('contact');
      } else {
        setView('home');
      }
    };

    window.addEventListener('popstate', handlePopState);
    handlePopState(); // Check on load

    return () => window.removeEventListener('popstate', handlePopState);
  }, []);

  const navigateToContact = (e?: React.MouseEvent) => {
    if (e) e.preventDefault();
    window.history.pushState({}, '', '#contact-form');
    setView('contact');
    window.scrollTo(0, 0);
  };

  const navigateToHome = (e?: React.MouseEvent) => {
    if (e) e.preventDefault();
    window.history.pushState({}, '', '#');
    setView('home');
    window.scrollTo(0, 0);
  };

  return (
    <div className="min-h-screen bg-zinc-950">
      <Navbar onContactClick={navigateToContact} onHomeClick={navigateToHome} isHome={view === 'home'} />
      <main>
        {view === 'home' ? (
          <>
            <Hero onContactClick={navigateToContact} />
            <AllyApproach onContactClick={navigateToContact} />
            <Services onContactClick={navigateToContact} />
            <MarketInsights onContactClick={navigateToContact} />
            <Contact onContactClick={navigateToContact} />
          </>
        ) : (
          <ContactPage onBackClick={navigateToHome} />
        )}
      </main>
    </div>
  );
};

